export default function LoginPage() {
  const clientId = process.env.NEXT_PUBLIC_GOOGLE_CLIENT_ID;

  if (!clientId) {
    return (
      <div className="min-h-screen bg-[#050505] flex items-center justify-center text-white p-4">
        <div className="text-center max-w-md p-8 bg-red-500/10 border border-red-500/30 rounded-2xl">
          <p className="text-[#ff6b35] font-black uppercase tracking-widest text-sm mb-4">Configuration Error</p>
          <p className="text-slate-300 text-xs font-medium leading-relaxed">
            The Google Client ID is missing. Please check your <code className="text-[#ff6b35]">.env.local</code> file and restart your development server.
          </p>
        </div>
      </div>
    );
  }

  return (
    <GoogleOAuthProvider clientId={clientId}>
      <LoginContent />
    </GoogleOAuthProvider>
  );
}

"use client";

import { useEffect, useState } from "react";
import Image from "next/image";
import { API_BASE_URL } from "@/lib/auth";

import Navbar from "@/components/landing/Navbar";
import HeroSection from "@/components/landing/HeroSection";
import FacilitiesSection from "@/components/landing/FacilitiesSection";
import Games from "@/components/landing/Games";
import AboutSection from "@/components/landing/AboutSection";
import LocationSection from "@/components/landing/LocationSection";
import Footer from "@/components/landing/Footer";

export default function Home() {
  const [desktopImages, setDesktopImages] = useState<string[]>([]);
  const [mobileImages, setMobileImages] = useState<string[]>([]);
  const [currentBgIndex, setCurrentBgIndex] = useState(0);

  // ≡ƒöÑ Fetch images from DB and filter by Desktop/Mobile Views
  useEffect(() => {
    async function fetchBackgrounds() {
      try {
        const res = await fetch(`${API_BASE_URL}/api/media`);
        const data = await res.json();

        if (data.items) {
          const desktop = data.items
            .filter((item: any) => item.category === "Application" && item.view === "Desktop")
            .map((item: any) => item.secure_url);

          const mobile = data.items
            .filter((item: any) => item.category === "Application" && item.view === "Mobile")
            .map((item: any) => item.secure_url);

          setDesktopImages(desktop.length > 0 ? desktop : ["https://res.cloudinary.com/dle9e8kwq/image/upload/v1778053508/Photos/Application/b2sroykaouke7ydut1ce.jpg"]);
          setMobileImages(mobile.length > 0 ? mobile : ["https://res.cloudinary.com/dle9e8kwq/image/upload/v1778053392/Photos/Application/vnuoihogngfcbrxvxfzm.jpg"]);
        }
      } catch (err) {
        console.error("Failed to load hero backgrounds:", err);
      }
    }
    fetchBackgrounds();
  }, []);

  // ≡ƒöÑ Slider Logic
  useEffect(() => {
    const maxLen = Math.max(desktopImages.length, mobileImages.length);
    if (maxLen <= 1) return;

    const interval = setInterval(() => {
      setCurrentBgIndex((prev) => (prev + 1) % maxLen);
    }, 5000); 
    return () => clearInterval(interval);
  }, [desktopImages.length, mobileImages.length]);

  return (
    <main className="bg-[#050505] min-h-screen text-white relative selection:bg-[#ff6b35] selection:text-white">

      {/* Slow Pan Animation CSS */}
      <style>{`
        @keyframes pan-image {
          0% { transform: scale(1.05) translateX(1%); }
          100% { transform: scale(1.05) translateX(-1%); }
        }
        .animate-pan {
          animation: pan-image 20s ease-in-out infinite alternate;
        }
      `}</style>

      {/* =========================================================
          ≡ƒöÑ GLOBAL FIXED DYNAMIC BACKGROUND
      ========================================================= */}
      <div className="fixed inset-0 z-0 overflow-hidden pointer-events-none">

        {/* DESKTOP VIEW */}
        <div className="hidden md:block w-full h-full relative">
          {desktopImages.map((src, idx) => (
            <div 
              key={`desktop-${idx}`}
              className={`absolute inset-0 w-full h-full transition-opacity duration-1000 ease-in-out ${
                idx === currentBgIndex ? "opacity-100 z-10" : "opacity-0 z-0"
              }`}
            >
              <div className="absolute inset-0 w-full h-full animate-pan">
                <Image src={src} alt="Desktop Background" fill priority={idx === 0} className="object-cover opacity-100" />
              </div>
            </div>
          ))}
        </div>

        {/* MOBILE VIEW */}
        <div className="block md:hidden w-full h-full relative">
          {mobileImages.map((src, idx) => (
            <div 
              key={`mobile-${idx}`}
              className={`absolute inset-0 w-full h-full transition-opacity duration-1000 ease-in-out ${
                idx === currentBgIndex ? "opacity-100 z-10" : "opacity-0 z-0"
              }`}
            >
              <div className="absolute inset-0 w-full h-full animate-pan">
                <Image src={src} alt="Mobile Background" fill priority={idx === 0} className="object-cover opacity-100" />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* =========================================================
          ≡ƒöÑ MAIN SCROLLING CONTENT
      ========================================================= */}
      <div className="relative z-10">

  <Navbar />

  <HeroSection />

  {/* DIVIDER */}
  <div className="flex justify-center px-6">
    <div className="w-full max-w-[1600px] h-[3px] rounded-full bg-gradient-to-r from-transparent via-[#FFFFFF]/70 to-transparent shadow-[0_0_25px_rgba(255,107,53,0.35)]"></div>
  </div>

  <FacilitiesSection />

  {/* DIVIDER */}
  <div className="flex justify-center px-6">
    <div className="w-full max-w-[1600px] h-[3px] rounded-full bg-gradient-to-r from-transparent via-white/40 to-transparent"></div>
  </div>

  <Games />

  {/* DIVIDER */}
  <div className="flex justify-center px-6">
    <div className="w-full max-w-[1600px] h-[3px] rounded-full bg-gradient-to-r from-transparent via-[#ff6b35]/60 to-transparent shadow-[0_0_20px_rgba(255,107,53,0.25)]"></div>
  </div>

  <AboutSection />

  {/* DIVIDER */}
  <div className="flex justify-center px-6">
    <div className="w-full max-w-[1600px] h-[3px] rounded-full bg-gradient-to-r from-transparent via-white/40 to-transparent"></div>
  </div>

  <LocationSection />

  {/* DIVIDER */}
  <div className="flex justify-center px-6">
    <div className="w-full max-w-[1600px] h-[3px] rounded-full bg-gradient-to-r from-transparent via-[#ff6b35]/70 to-transparent shadow-[0_0_25px_rgba(255,107,53,0.35)]"></div>
  </div>

  <Footer />

</div>
    </main>
  );
}

"use client";

import { useState } from "react";
import { useRouter, useParams } from "next/navigation";
import { API_BASE_URL } from "@/lib/auth";

export default function ResetPasswordPage() {
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const { token } = useParams();

  const handleReset = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await fetch(`${API_BASE_URL}/api/auth/reset-password/${token}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ password }),
      });
      const data = await res.json();
      setMessage(data.message);
      if (res.ok) setTimeout(() => router.push("/login"), 2000);
    } catch (err) {
      setMessage("Something went wrong.");
    } finally {
      setLoading(false);
    }
  };

  const clipPathStyle = { clipPath: "polygon(12px 0, 100% 0, 100% calc(100% - 12px), calc(100% - 12px) 100%, 0 100%, 0 12px)" };

  return (
    <div className="min-h-screen bg-[#0A0A0A] flex items-center justify-center p-6">
      <div className="w-full max-w-md bg-[#0A0A0A] border border-white/10 p-10 rounded-2xl shadow-2xl">
        <h1 className="text-2xl font-black text-white uppercase mb-6 tracking-tighter">NEW <span className="text-[#ff6b35]">PASSWORD</span></h1>
        <form onSubmit={handleReset} className="space-y-6">
          <div style={clipPathStyle} className="bg-[#ff6b35] p-[1.5px]">
            <input 
              type="password" 
              required 
              placeholder="ENTER NEW PASSWORD" 
              className="w-full bg-[#0A0A0A] px-5 py-3 text-xs text-white outline-none" 
              style={clipPathStyle}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-[#ff6b35] py-4 text-xs font-black text-white uppercase tracking-widest hover:bg-[#e05928]" 
            style={clipPathStyle}
          >
            {loading ? "UPDATING..." : "UPDATE PASSWORD"}
          </button>
        </form>
        {message && <p className="text-[10px] text-center font-bold text-[#ff6b35] mt-6 uppercase tracking-widest">{message}</p>}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";

import {
  API_BASE_URL,
  type Profile,
} from "@/lib/auth";

import SettingsMobileMenu from "@/components/dashboard/settings/SettingsMobileMenu";
import AccountTab from "@/components/dashboard/settings/AccountTab";
import SecurityTab from "@/components/dashboard/settings/SecurityTab";
import NotificationTab from "@/components/dashboard/settings/NotificationTab";
import SettingsSidebar from "@/components/dashboard/settings/SettingsSidebar";

export default function SettingsPage() {

  const [profile, setProfile] =
    useState<Profile | null>(null);

  const [isLoading, setIsLoading] =
    useState(true);

  const [activeTab, setActiveTab] =
    useState("account");

  const [isMobileMenuOpen, setIsMobileMenuOpen] =
    useState(false);

  // =========================================================
  // FETCH PROFILE
  // =========================================================

  const fetchFreshProfile =
    async (token: string) => {

      const res = await fetch(
        `${API_BASE_URL}http://192.168.1.16:5000?t=${Date.now()}`,
        {
          method: "GET",
          headers: {
            Authorization: `Bearer ${token}`,
          },
          cache: "no-store",
        }
      );

      if (!res.ok) {
        throw new Error(
          "Failed to fetch profile"
        );
      }

      return await res.json();

    };

  // =========================================================
  // LOAD PROFILE
  // =========================================================

  useEffect(() => {

    const token =
      localStorage.getItem(
        "auth_token"
      ) || "";

    if (!token) {

      window.location.href =
        "/login";

      return;

    }

    const savedProfile =
      localStorage.getItem(
        "profile"
      );

    if (savedProfile) {

      try {

        setProfile(
          JSON.parse(savedProfile)
        );

      } catch (err) {

        console.error(err);

      }

    }

    async function loadData() {

      try {

        setIsLoading(true);

        const data =
          await fetchFreshProfile(
            token
          );

        localStorage.setItem(
          "profile",
          JSON.stringify(data)
        );

        setProfile(data);

      } catch (err) {

        console.error(err);

      } finally {

        setIsLoading(false);

      }

    }

    loadData();

  }, []);

  // =========================================================
  // REFRESH PROFILE
  // =========================================================

  const refreshProfile =
    async (updatedUser?: any) => {

      if (updatedUser) {

        localStorage.setItem(
          "profile",
          JSON.stringify(updatedUser)
        );

        setProfile(updatedUser);

        return;

      }

      const token =
        localStorage.getItem(
          "auth_token"
        );

      if (token) {

        const updatedProfile =
          await fetchFreshProfile(
            token
          );

        localStorage.setItem(
          "profile",
          JSON.stringify(updatedProfile)
        );

        setProfile(updatedProfile);

      }

    };

  // =========================================================
  // LOGOUT
  // =========================================================

  const handleLogout = () => {

    localStorage.clear();

    window.location.href =
      "/login";

  };

  // =========================================================
  // INITIALS
  // =========================================================

  const getInitials = (
    name?: string
  ) => {

    if (!name) return "U";

    return name
      .trim()
      .split(/\s+/)
      .slice(0, 2)
      .map((p) =>
        p[0]?.toUpperCase()
      )
      .join("");

  };

  // =========================================================
  // NAV ITEMS
  // =========================================================

  const navItems = [
    {
      name: "Dashboard",
      href: "/dashboard",
    },

    {
      name: "Book Slot",
      href: "/book",
    },

    {
      name: "My Sessions",
      href: "/dashboard#history",
    },

    {
      name: "Games Library",
      href: "/dashboard#games",
    },

    {
      name: "Settings",
      href: "/settings",
    },

    {
      name: "Help & Support",
      href: "/help-support",
    },
  ];

  // =========================================================
  // LOADER
  // =========================================================

  if (isLoading) {

    return (

      <div className="flex min-h-screen items-center justify-center bg-[#FDF8F5]">

        <div className="flex flex-col items-center gap-4">

          <div className="h-12 w-12 animate-spin rounded-full border-4 border-[#ff6b35]/20 border-t-[#ff6b35]" />

          <p className="text-sm font-black uppercase tracking-widest text-[#ff6b35]">
            Loading Settings...
          </p>

        </div>

      </div>

    );

  }

  return (

    <div className="flex h-screen w-full bg-[#FDF8F5] text-[#1A1A1A] overflow-hidden relative">

      {/* GRID */}

      <div className="absolute inset-0 z-0 opacity-40 pointer-events-none bg-[linear-gradient(to_right,#80808020_1px,transparent_1px),linear-gradient(to_bottom,#80808020_1px,transparent_1px)] bg-[size:24px_24px]" />

      {/* MOBILE MENU */}

      <SettingsMobileMenu
  isOpen={isMobileMenuOpen}
  setIsOpen={setIsMobileMenuOpen}
  activeTab={activeTab}
  setActiveTab={setActiveTab}
  profile={profile}
  getInitials={getInitials}
/>

      {/* SIDEBAR */}

      <div className="hidden md:block w-[20%] h-full shrink-0 z-40">

        <SettingsSidebar
          activeTab={activeTab}
          setActiveTab={
            setActiveTab
          }
          profile={profile}
          getInitials={getInitials}
        />

      </div>

      {/* MAIN */}

      <div className="flex flex-col flex-1 min-w-0 relative z-10">

        {/* HEADER */}

<div className="h-[82px] shrink-0 border-b border-[#ff6b35]/10 bg-[#FDF8F5]/90 backdrop-blur-xl px-6">

  <div className="h-full flex items-center justify-between">

    {/* LEFT */}

    <div>

      <p className="text-[10px] font-black uppercase tracking-[0.3em] text-[#ff6b35] mb-1">
        Account Center
      </p>

      <h1 className="text-2xl font-black uppercase tracking-tight">
        Settings
      </h1>

    </div>

    {/* RIGHT */}

    <div className="flex items-center gap-4">

      {/* MOBILE MENU BUTTON */}

      <button
        onClick={() =>
          setIsMobileMenuOpen(
            true
