                <p className="text-[9px] font-bold uppercase tracking-wider text-[#ff6b35] mt-1.5 opacity-80">
                  {img.category === "Facilities" && img.facilityType ? `Type: ${img.facilityType}` : 
                   img.gameName ? `Game: ${img.gameName}` : 
