export default function Header({

  profile,

  setIsMobileMenuOpen,

  getInitials,

  handleLogout,

}: HeaderProps) {

  return (

    <header className="flex items-center justify-between w-full">

      {/* ===================================================== */}
      {/* LEFT SIDE */}
      {/* ===================================================== */}

      <div className="flex items-center">

        {/* DESKTOP WELCOME */}

        <div className="hidden md:block">

          <h1 className="font-display text-3xl text-[#1A1A1A] sm:text-4xl tracking-tight">

            Welcome back,{" "}

            <span className="text-[#ff6b35]">

              {profile?.name?.split(" ")[0] ||
                "Player"}

            </span>{" "}

            ≡ƒæï

          </h1>

          <p className="mt-2 text-xs font-bold tracking-[0.18em] uppercase text-slate-500">

            <span className="text-[#ff6b35]">

              JKS Arena

            </span>{" "}

            ΓÇó Ready for your next gaming session

          </p>

        </div>

        {/* MOBILE LOGO */}

        <div className="md:hidden">

          <h1 className="font-display text-2xl font-black tracking-wide">

            <span className="text-[#1A1A1A]">
              JKS
            </span>

            <span className="text-[#ff6b35]">
              {" "}
              ARENA
            </span>

          </h1>

        </div>

      </div>

      {/* ===================================================== */}
      {/* MOBILE RIGHT SIDE */}
      {/* ===================================================== */}

      <div className="md:hidden flex items-center gap-3 flex-row-reverse">

        {/* MENU BUTTON */}

        <button
          onClick={() =>
            setIsMobileMenuOpen(
              true
            )
          }
          className="flex items-center justify-center w-11 h-11 rounded-2xl border border-[#ff6b35]/20 bg-white shadow-sm text-slate-500 hover:text-[#ff6b35] hover:border-[#ff6b35]/40 transition-all duration-300"
        >

          <svg
            className="w-6 h-6"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >

            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M4 6h16M4 12h16M4 18h16"
            />

          </svg>

        </button>

        {/* NOTIFICATION BELL */}

        <NotificationBell />

        {/* PROFILE DROPDOWN */}

        <div className="relative">

          <details
            className="group"
            onClick={(e) => {

              const details =
                e.currentTarget;

              setTimeout(() => {

                const handleOutsideClick =
                  (
                    event: MouseEvent
                  ) => {

                    if (
                      !details.contains(
                        event.target as Node
                      )
                    ) {

                      details.removeAttribute(
                        "open"
                      );

                      document.removeEventListener(
                        "click",
                        handleOutsideClick
                      );

                    }

                  };

                document.addEventListener(
                  "click",
                  handleOutsideClick
                );

              }, 0);

            }}
          >

            <summary className="list-none cursor-pointer">

              <div className="group flex items-center gap-3 rounded-2xl border border-[#ff6b35]/15 bg-white px-3 py-2 shadow-[0_4px_15px_rgba(255,107,53,0.06)]">

                {/* AVATAR */}

                <div className="relative flex h-10 w-10 shrink-0 overflow-hidden items-center justify-center rounded-full bg-[#FDF8F5] border-2 border-[#ff6b35] text-xs font-black text-[#ff6b35]">

                  {profile?.avatarUrl ? (

                    <img
                      key={
                        profile?.avatarUrl ||
                        "mobile-avatar"
                      }
                      src={`${profile?.avatarUrl}?t=${Date.now()}`}
                      alt="Avatar"
                      className="w-full h-full object-cover"
                    />

                  ) : (

                    getInitials(
                      profile?.name
                    )

                  )}

                </div>

                {/* USER DETAILS */}

                <div className="flex flex-col min-w-0">

                  <p className="text-[11px] font-black uppercase tracking-[0.08em] text-[#1A1A1A] leading-none truncate max-w-[90px]">

                    {profile?.name ||
                      "Player"}

                  </p>

                  <p className="text-[10px] text-slate-500 mt-1 truncate max-w-[90px]">

                    {profile?.email ||
                      "player@jksarena.com"}

                  </p>

                </div>

              </div>

            </summary>

            {/* DROPDOWN */}

            <div className="absolute right-0 mt-3 w-52 overflow-hidden rounded-2xl border border-[#ff6b35]/20 bg-white/95 backdrop-blur-2xl shadow-[0_10px_40px_rgba(0,0,0,0.08)] z-50">

              {/* PROFILE */}

              <a
                href="/settings"
                className="flex w-full items-center gap-3 px-4 py-4 text-left text-sm font-bold text-[#1A1A1A] hover:bg-[#ff6b35]/5 hover:text-[#ff6b35] transition-all duration-300"
              >

                <svg
                  className="w-5 h-5"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >

                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M5.121 17.804A9 9 0 1118.88 17.8M15 11a3 3 0 11-6 0 3 3 0 016 0z"
                  />

                </svg>

                Profile

              </a>

              {/* LOGOUT */}

              <button
                onClick={handleLogout}
                className="flex w-full items-center gap-3 px-4 py-4 text-left text-sm font-bold text-red-500 hover:bg-red-50 hover:text-red-600 transition-all duration-300 border-t border-slate-100"
              >

                <svg
                  className="w-5 h-5"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >

                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1m0-10V7m-6 14h6a2 2 0 002-2V5a2 2 0 00-2-2H7a2 2 0 00-2 2v14a2 2 0 002 2z"
                  />

                </svg>

                Logout

              </button>

            </div>

          </details>

        </div>

      </div>

      {/* ===================================================== */}
      {/* DESKTOP PROFILE */}
      {/* ===================================================== */}

      <div className="hidden md:flex items-center gap-4">

        {/* NOTIFICATION BELL */}

        <NotificationBell />

        {/* PROFILE CARD */}

        <div className="group flex items-center gap-4 rounded-3xl border border-[#ff6b35]/15 bg-white px-4 py-3 shadow-[0_8px_30px_rgba(255,107,53,0.08)] hover:border-[#ff6b35]/40 transition-all duration-300">

          {/* AVATAR */}

          <div className="relative">

            {/* GLOW */}

            <div className="absolute inset-0 rounded-full bg-[#ff6b35]/20 blur-lg opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>

            <div className="relative flex h-14 w-14 overflow-hidden items-center justify-center rounded-full bg-white border-2 border-[#ff6b35] text-sm font-black text-[#ff6b35] shadow-sm">

              {profile?.avatarUrl ? (

                <img
                  key={
                    profile?.avatarUrl ||
                    "desktop-avatar"
                  }
                  src={`${profile?.avatarUrl}?t=${Date.now()}`}
                  alt="Avatar"
                  className="w-full h-full object-cover"
                />

              ) : (

                <span className="text-lg">

                  {getInitials(
                    profile?.name
                  )}

                </span>

              )}

            </div>

            {/* ONLINE DOT */}

            <div className="absolute bottom-0 right-0 w-4 h-4 rounded-full bg-green-500 border-2 border-white shadow-[0_0_8px_rgba(34,197,94,0.4)]"></div>

          </div>

          {/* USER DETAILS */}

          <div className="flex flex-col">

            <p className="text-sm font-black uppercase tracking-[0.08em] text-[#1A1A1A] leading-none">

              {profile?.name ||
                "Player"}

            </p>

            <p className="text-xs text-slate-500 mt-1 tracking-wide">

              {profile?.email ||
                "player@jksarena.com"}

            </p>

          </div>

        </div>

      </div>

    </header>

  );

}

"use client";

import Link from "next/link";
import { useEffect, useState } from "react";

interface LiveArenaStatusProps {
  bookings: any[];
}

export default function LiveArenaStatus({
  bookings,
}: LiveArenaStatusProps) {

  const [currentTime, setCurrentTime] =
    useState(Date.now());

  // =========================================================
  // AUTO REFRESH STATUS
  // =========================================================

  useEffect(() => {

    const interval = setInterval(
      () => setCurrentTime(Date.now()),
      60000
    );

    return () =>
      clearInterval(interval);

  }, []);

  // =========================================================
  // CHECK SLOT STATUS
  // =========================================================

  const checkIsOccupied = (
    deviceCode: string
  ) => {

    return bookings.some(
      (booking) => {

        const matchDevice =
          booking.device
            .replace(/\s+/g, "")
            .toUpperCase() ===
          deviceCode
            .replace(/\s+/g, "")
            .toUpperCase();

        if (
          !matchDevice ||
          booking.status ===
            "cancelled"
        ) {
          return false;
        }

        const startTime =
          new Date(
            booking.slotStart
          ).getTime();

        const endTime =
          startTime +
          booking.durationHours *
            60 *
            60 *
            1000;

        return (
          booking.status ===
            "active" ||
          (currentTime >=
            startTime &&
            currentTime <
              endTime)
        );

      }
    );

  };

  // =========================================================
  // PS5 SLOTS
  // =========================================================

  const ps5Slots = [
    "PS1",
    "PS2",
    "PS3",
    "PS4",
  ].map((id) => {

    const isOccupied =
      checkIsOccupied(id);

    return {
      id,
      status: isOccupied
        ? "OCCUPIED"
        : "AVAILABLE",
      color: isOccupied
        ? "bg-red-500"
        : "bg-green-500",
      text: isOccupied
        ? "text-red-600"
        : "text-green-600",
    };

  });

  // =========================================================
  // SIMULATOR SLOTS
  // =========================================================

  const simSlots = [
    "SIM 1",
    "SIM 2",
  ].map((id) => {

    const isOccupied =
      checkIsOccupied(id);

    return {
      id,
      status: isOccupied
        ? "OCCUPIED"
        : "AVAILABLE",
      color: isOccupied
        ? "bg-red-500"
        : "bg-green-500",
      text: isOccupied
        ? "text-red-600"
        : "text-green-600",
    };

  });

  return (

    <div className="flex flex-col bg-[#FDF8F5] border border-[#1A1A1A] rounded-[2rem] p-6 md:p-8 shadow-[0_8px_30px_rgba(0,0,0,0.04)] h-full">

      {/* HEADER */}

      <div className="flex justify-between items-center mb-8">

        <div className="flex items-center gap-2">

          <svg
            className="w-5 h-5 text-[#ff6b35]"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >

            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M13 10V3L4 14h7v7l9-11h-7z"
            />

          </svg>

          <h3 className="text-sm font-black uppercase tracking-widest text-[#1A1A1A]">
            Live Arena Status
          </h3>

        </div>

        <Link
          href="#"
          className="text-[10px] font-bold uppercase tracking-widest text-[#ff6b35] hover:text-[#1A1A1A] transition-colors"
        >
          View All
        </Link>

      </div>

      {/* CONTENT */}

      <div className="space-y-8 flex-1">

        {/* PS5 ARENA */}

        <div>

          <div className="flex justify-between items-end mb-4">

            <p className="text-sm font-black text-[#1A1A1A]">
              PS5 Arena
            </p>

            <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">
              4 Slots
            </p>

          </div>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">

            {ps5Slots.map(
              (slot) => (

                <div
                  key={slot.id}
                  className="bg-white border border-[#1A1A1A]/10 rounded-2xl p-4 flex flex-col items-center justify-center gap-2 shadow-sm"
                >

                  <span className="text-xs font-black text-[#1A1A1A]">
                    {slot.id}
                  </span>

                  <div className="flex items-center gap-1.5 bg-slate-50 px-2 py-1 rounded-full border border-slate-100">

                    <span
                      className={`w-1.5 h-1.5 rounded-full ${slot.color}`}
                    />

                    <span
                      className={`text-[8px] font-bold tracking-widest uppercase ${slot.text}`}
                    >

                      {slot.status}

                    </span>

                  </div>

                </div>

              )
            )}

          </div>

        </div>

        {/* SIMULATOR */}

        <div>

          <div className="flex justify-between items-end mb-4">

            <p className="text-sm font-black text-[#1A1A1A]">
              Simulator Zone
            </p>

            <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">
              2 Slots
            </p>

          </div>

          <div className="grid grid-cols-2 gap-3">

            {simSlots.map(
              (slot) => (

                <div
                  key={slot.id}
                  className="bg-white border border-[#1A1A1A]/10 rounded-2xl p-4 flex items-center justify-between px-5 shadow-sm"
                >

                  <span className="text-xs font-black text-[#1A1A1A]">
                    {slot.id}
                  </span>

                  <div className="flex items-center gap-1.5 bg-slate-50 px-2.5 py-1.5 rounded-full border border-slate-100">

                    <span
                      className={`w-1.5 h-1.5 rounded-full ${slot.color}`}
                    />

                    <span
                      className={`text-[8px] font-bold tracking-widest uppercase ${slot.text}`}
                    >

                      {slot.status}

                    </span>

                  </div>

                </div>

              )
            )}

          </div>

        </div>

      </div>

      {/* BOOK BUTTON */}

      <div className="mt-8 pt-6 border-t border-[#1A1A1A]/10">

        <Link
          href="/book"
          className="group relative flex items-center justify-center gap-3 w-full overflow-hidden rounded-2xl bg-[#ff6b35] px-6 py-4 text-white shadow-[0_8px_25px_rgba(255,107,53,0.28)] transition-all duration-300 hover:scale-[1.01] hover:bg-[#eb5d2a]"
        >

          <div className="absolute inset-0 bg-gradient-to-r from-white/0 via-white/10 to-white/0 translate-x-[-120%] group-hover:translate-x-[120%] transition-transform duration-1000"></div>

          <svg
            className="relative z-10 w-5 h-5"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >

            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M8 7V3m8 4V3m-9 8h10m-11 9h12a2 2 0 002-2V7a2 2 0 00-2-2H6a2 2 0 00-2 2v11a2 2 0 002 2z"
            />

          </svg>

          <span className="relative z-10 text-[11px] font-black uppercase tracking-[0.28em]">
            Book My Slot
          </span>

        </Link>

      </div>

    </div>

  );

}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useEffect, useState } from "react";
import { Profile } from "@/lib/auth";

interface MobileMenuProps {
  isOpen: boolean;
  setIsOpen: (isOpen: boolean) => void;
  profile: Profile | null;
  getInitials: (name?: string) => string;
  handleLogout: () => void;
  navItems?: any;
}

const menuItems = [
  {
    name: "Dashboard",
    href: "/dashboard",
    icon: DashboardIcon,
  },

  {
    name: "Book Slot",
    href: "/book",
    icon: CalendarIcon,
  },

  {
    name: "My Sessions",
    href: "/dashboard#history",
    icon: SessionsIcon,
  },

  {
    name: "Games Library",
    href: "/dashboard#games",
    icon: GamepadIcon,
  },

  {
    name: "Settings",
    href: "/settings",
    icon: SettingsIcon,
  },

  {
    name: "Help & Support",
    href: "/help-support",
    icon: HelpIcon,
  },
];

export default function MobileMenu({
  isOpen,
  setIsOpen,
  profile,
  getInitials,
  handleLogout,
}: MobileMenuProps) {

  const pathname = usePathname();

  const [activeHash, setActiveHash] =
    useState("");

  useEffect(() => {

    setActiveHash(
      window.location.hash
    );

    const handleHashChange =
      () =>
        setActiveHash(
          window.location.hash
        );

    window.addEventListener(
      "hashchange",
      handleHashChange
    );

    return () =>
      window.removeEventListener(
        "hashchange",
        handleHashChange
      );

  }, []);

  const isActive = (
    href: string
  ) => {

    if (href.startsWith("#")) {
      return activeHash === href;
    }

    if (href === "/dashboard") {
      return (
        pathname === "/dashboard" &&
        activeHash === ""
      );
    }

    return pathname === href;

  };

  return (

    <>

      {/* OVERLAY */}

      <div
        onClick={() =>
          setIsOpen(false)
        }
        className={`fixed inset-0 z-[90] bg-[#1A1A1A]/60 backdrop-blur-sm transition-all duration-300 md:hidden ${
          isOpen

            ? "opacity-100 pointer-events-auto"

            : "opacity-0 pointer-events-none"
        }`}
      />

      {/* MENU */}

      <div
        className={`fixed top-0 right-0 z-[100] w-72 h-screen bg-[#F3EFEC] border-l border-[#1A1A1A]/10 pt-6 pb-6 px-4 shadow-2xl flex flex-col justify-between transition-transform duration-500 ease-[cubic-bezier(0.22,1,0.36,1)] md:hidden ${
          isOpen

            ? "translate-x-0"

            : "translate-x-full"
        }`}
      >

        {/* TOP SECTION */}

        <div>

          {/* HEADER */}

          <div className="flex justify-between items-center mb-8 px-2">

            <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-[#ff6b35]">

              Menu

            </p>

            {/* CLOSE */}

            <button
              onClick={() =>
                setIsOpen(false)
              }
              className="text-slate-500 hover:text-[#ff6b35] transition-colors p-2 -mr-2 bg-white rounded-full border border-[#1A1A1A]/10 shadow-sm"
            >

              <svg
                className="w-5 h-5"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >

                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />

              </svg>

            </button>

          </div>

          {/* NAVIGATION */}

          <nav className="space-y-1.5 px-2">

            {menuItems.map((item) => {

              const active =
                isActive(item.href);

              return (

                <Link
                  key={item.name}
                  href={item.href}
                  onClick={() => {

                    if (
                      item.href.startsWith(
                        "#"
                      )
                    ) {

                      setActiveHash(
                        item.href
                      );

                    }

                    if (
                      item.href ===
                      "/dashboard"
                    ) {

                      setActiveHash("");

                    }

                    setTimeout(
                      () =>
                        setIsOpen(
                          false
                        ),
                      150
                    );

                  }}
                  className={`flex items-center px-4 py-3.5 rounded-2xl transition-all duration-300 group ${
                    active

                      ? "bg-[#ff6b35] text-white shadow-[0_4px_15px_rgba(255,107,53,0.3)]"

                      : "text-slate-500 hover:bg-[#ff6b35]/5 hover:text-[#ff6b35]"
                  }`}
                >

                  <div className="flex items-center gap-4">

                    <item.icon
                      className={`w-5 h-5 transition-colors ${
                        active

                          ? "text-white"

                          : "text-slate-400 group-hover:text-[#ff6b35]"
                      }`}
                    />

                    <span
                      className={`text-[13px] font-bold tracking-wide ${
                        active
                          ? "text-white"
                          : ""
                      }`}
                    >

                      {item.name}

                    </span>

                  </div>

                </Link>

              );

            })}

          </nav>

        </div>

        {/* BOTTOM PROFILE & LOGOUT */}

        <div className="mt-8 px-2">

          {/* PROFILE CARD */}

          <div className="group flex items-center gap-4 rounded-3xl border border-[#1A1A1A]/10 bg-white px-4 py-4 shadow-sm hover:border-[#ff6b35]/40 transition-all duration-300 mb-4">

            {/* AVATAR */}

            <div className="relative">

              <div className="absolute inset-0 rounded-full bg-[#ff6b35]/20 blur-lg opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>

              <div className="relative flex h-12 w-12 overflow-hidden items-center justify-center rounded-full bg-[#FDF8F5] border-2 border-[#ff6b35] text-sm font-black text-[#ff6b35] shadow-sm">

                {profile?.avatarUrl ? (

                  <img
                    key={
                      profile.avatarUrl
                    }
                    src={`${profile.avatarUrl}?t=${Date.now()}`}
                    alt="Avatar"
                    className="w-full h-full object-cover"
                  />

                ) : (

                  <span className="text-lg">

                    {getInitials(
                      profile?.name
                    )}

                  </span>

                )}

              </div>

              {/* ONLINE DOT */}

              <div className="absolute bottom-0 right-0 w-3.5 h-3.5 rounded-full bg-green-500 border-2 border-white shadow-[0_0_8px_rgba(34,197,94,0.4)]"></div>

            </div>

            {/* USER DETAILS */}

            <div className="flex flex-col overflow-hidden">

              <p className="text-sm font-black uppercase tracking-[0.08em] text-[#1A1A1A] leading-none truncate">

                {profile?.name ||
                  "Player"}

              </p>

              <p className="text-xs text-slate-500 mt-1 tracking-wide truncate">

                {profile?.email ||
                  "player@jksarena.com"}

              </p>

            </div>

          </div>

          {/* LOGOUT BUTTON */}

          <button
            onClick={handleLogout}
            className="group relative w-full overflow-hidden rounded-2xl border border-[#ff6b35]/30 bg-white px-4 py-3.5 text-[#ff6b35] shadow-sm transition-all duration-300 hover:bg-[#ff6b35] hover:text-white hover:border-[#ff6b35]"
          >

            <span className="relative z-10 flex items-center justify-center gap-3 text-[12px] font-black uppercase tracking-[0.25em]">

              <LogoutIcon className="w-5 h-5 transition-colors" />

              Logout

            </span>

          </button>

        </div>

      </div>

    </>

  );

}

// Icons

function DashboardIcon(props: any) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      <path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path>
      <polyline points="9 22 9 12 15 12 15 22"></polyline>
    </svg>
  );
}

function CalendarIcon(props: any) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      <rect
        x="3"
        y="4"
        width="18"
        height="18"
        rx="2"
        ry="2"
      ></rect>

      <line
        x1="16"
        y1="2"
        x2="16"
        y2="6"
      ></line>

      <line
        x1="8"
        y1="2"
        x2="8"
