        <h2 className="text-sm font-black uppercase tracking-widest text-[#ff6b35]">Recent Sessions</h2>
        
        <div className="flex gap-3">
          <select 
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
