              className="group flex flex-col rounded-3xl border border-[#1A1A1A]/20 bg-white p-5 shadow-sm transition-all hover:-translate-y-1 hover:shadow-md cursor-pointer hover:border-[#1A1A1A] relative overflow-hidden"
