                <p className="text-[10px] font-bold text-[#ff6b35] uppercase tracking-widest">
                  {booking.players} Player{booking.players > 1 ? 's' : ''}
                </p>
                <p className="text-lg font-black text-[#1A1A1A]">Γé╣{booking.totalPrice}</p>
              </div>
            </div>
          ))
        )}
      </div>
    </section>
  );
}

