// =========================================================
// ≡ƒöÑ AUTH REQUEST HELPER
// =========================================================

async function requestAuth(
  path: string,
  payload: Record<string, string>
) {

  const response = await fetch(
    `${API_BASE_URL}${path}`,
    {

      method: "POST",

      headers: {

        "Content-Type":
          "application/json",

      },

      body: JSON.stringify(
        payload
      ),

    }
  );

  const data =
    (await response.json()) as {

      message?: string;

    } & AuthResponse;

  if (!response.ok) {

    throw new Error(
      data.message ||
        "Request failed"
    );

  }

  return data;

}

// =========================================================
// ≡ƒöÑ REGISTER
// =========================================================

export function registerUser(
  payload: {

    name: string;

    email: string;

    password: string;

  }
) {

  return requestAuth(
    "/api/auth/register",
    payload
  );

}

// =========================================================
// ≡ƒöÑ LOGIN
// =========================================================

export async function loginUser(
  payload: {

    email: string;

    password: string;

  }
) {

  const data =
    await requestAuth(
      "/api/auth/login",
      payload
    );

  // =====================================================
  // ≡ƒöÑ SAVE LOGIN DATA
  // =====================================================

  if (typeof window !== "undefined") {

    // ≡ƒöÑ SAVE PROFILE
    localStorage.setItem(
      "profile",
      JSON.stringify(
        data.user
      )
    );

    // ≡ƒöÑ SAVE JWT TOKEN
    localStorage.setItem(
      "token",
      data.token
    );

    // ≡ƒöÑ SAVE ROLE
    localStorage.setItem(
      "role",
      data.role
    );

  }

  return {

    ...data,

    user: {

      id:
        data.user?.id || "",

      name:
        data.user?.name || "",

      email:
        data.user?.email || "",

      avatarUrl:
        data.user?.avatarUrl || "",

    },

  };

}

// =========================================================
// ≡ƒöÑ LOGOUT
// =========================================================

export function logoutUser() {

  if (typeof window === "undefined") {
    return;
  }

  localStorage.removeItem(
    "token"
  );

  localStorage.removeItem(
    "profile"
  );

  localStorage.removeItem(
    "role"
  );

}

// =========================================================
// ≡ƒöÑ TOKEN REQUEST HELPER
// =========================================================

async function requestWithToken<T>(
  path: string,
  token: string
) {

  const response = await fetch(
    `${API_BASE_URL}${path}`,
    {

      method: "GET",

      headers: {

        Authorization:
          `Bearer ${token}`,

        "Cache-Control":
          "no-cache, no-store, must-revalidate",

        Pragma:
          "no-cache",

        Expires:
          "0",

      },

      cache: "no-store",

    }
  );

  const data =
    (await response.json()) as {

      message?: string;

    } & T;

  if (!response.ok) {

    throw new Error(
      data.message ||
        "Request failed"
    );

  }

  return data;

}

