export async function fetchProfile(
  token: string
): Promise<Profile> {

  const data =
    await requestWithToken<any>(
      "http://192.168.1.16:5000",
      token
    );

  // ≡ƒöÑ SAVE PROFILE

  if (typeof window !== "undefined") {

    localStorage.setItem(
      "profile",
      JSON.stringify(data)
    );

  }

  return {

    id:
      data._id ||
      data.id ||
      "",

    _id:
      data._id ||
      data.id ||
      "",

    name:
      data.name || "",

    email:
      data.email || "",

    avatarUrl:
      data.avatarUrl || "",

    currentPlan:
      data.currentPlan || null,

    notifications:
      data.notifications || {

        bookingUpdates: true,

        sessionReminders: true,

        newGames: true,

      },

  };

}

